"""stl_validator_improved.py — improved STL validation tool.

Handles both binary and ASCII STL files. Checks:
- Triangle count (must be > 0)
- Manifold integrity (every edge shared by exactly 2 triangles)
- Face normal consistency (declared normal vs winding order)
- Degenerate triangles (zero-area faces)
- Surface area computation

Usage: python stl_validator_improved.py <file.stl>
Output: JSON object {"valid": true/false, "issues": [...], ...}
"""
import json
import math
import struct
import sys


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )

def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])

def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]

def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)

def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return v
    return (v[0] / m, v[1] / m, v[2] / m)

def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def _is_binary_stl(path: str) -> bool:
    try:
        with open(path, "rb") as fh:
            header = fh.read(84)
        if len(header) < 84:
            return False
        num_triangles = struct.unpack_from("<I", header, 80)[0]
        import os
        file_size = os.path.getsize(path)
        expected_size = 84 + num_triangles * 50
        if file_size == expected_size and num_triangles > 0:
            return True
        ascii_start = header[:5].lower() == b"solid"
        if not ascii_start:
            return True
        return False
    except OSError:
        return False


def _parse_binary(path: str):
    issues = []
    triangles = []
    with open(path, "rb") as fh:
        data = fh.read()
    if len(data) < 84:
        issues.append("File too short to be a valid binary STL")
        return triangles, issues
    num_triangles = struct.unpack_from("<I", data, 80)[0]
    expected_size = 84 + num_triangles * 50
    if len(data) != expected_size:
        issues.append(
            f"File size mismatch: expected {expected_size} bytes for "
            f"{num_triangles} triangles, got {len(data)} bytes"
        )
    offset = 84
    for i in range(num_triangles):
        if offset + 50 > len(data):
            issues.append(f"Truncated data at triangle {i + 1}")
            break
        nx, ny, nz = struct.unpack_from("<fff", data, offset)
        v1 = struct.unpack_from("<fff", data, offset + 12)
        v2 = struct.unpack_from("<fff", data, offset + 24)
        v3 = struct.unpack_from("<fff", data, offset + 36)
        triangles.append(((nx, ny, nz), [v1, v2, v3]))
        offset += 50
    return triangles, issues


def _parse_ascii(path: str):
    issues = []
    triangles = []
    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue
            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1
            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue
        i += 1
    return triangles, issues


def _validate_triangles(triangles, issues):
    if not triangles:
        issues.append("No valid faces found")
        return
    degenerate_count = sum(
        1 for _, verts in triangles if _triangle_area(*verts) < 1e-10
    )
    if degenerate_count > 0:
        issues.append(f"{degenerate_count} degenerate (zero-area) triangle(s) found")
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1
    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    non_manifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")
    if non_manifold_edges > 0:
        issues.append(f"Mesh has {non_manifold_edges} non-manifold edge(s) (shared by >2 triangles)")
    inverted_count = 0
    for declared_normal, verts in triangles:
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        cross = _cross(edge1, edge2)
        if _magnitude(cross) < 1e-10:
            continue
        winding_normal = _normalize(cross)
        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            continue
        similarity = _dot(_normalize(declared_normal), winding_normal)
        if similarity < 0:
            inverted_count += 1
    if inverted_count > 0:
        issues.append(f"{inverted_count} face(s) have normals inconsistent with winding order")


def validate_stl(path: str) -> dict:
    """Validate an STL file (binary or ASCII) for manufacturing suitability."""
    issues = []
    binary = _is_binary_stl(path)
    if binary:
        triangles, parse_issues = _parse_binary(path)
    else:
        triangles, parse_issues = _parse_ascii(path)
    issues.extend(parse_issues)
    _validate_triangles(triangles, issues)
    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)
    return {
        "valid": len(issues) == 0,
        "format": "binary" if binary else "ascii",
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved.py <file.stl>"}))
        sys.exit(1)
    result = validate_stl(sys.argv[1])
    print(json.dumps(result))
